using System.Numerics;
using UniswapSharp.Core;
using UniswapSharp.Core.Entities;
using UniswapSharp.Core.Entities.Fractions;
using UniswapSharp.Router;
using UniswapSharp.Router.Entities;
using UniswapSharp.Router.Entities.MixedRoute;
using UniswapSharp.V3.Utils;
using V2Pair = UniswapSharp.V2.Entities.Pair;
using V2Route = UniswapSharp.V2.Entities.Route<UniswapSharp.Core.Entities.BaseCurrency, UniswapSharp.Core.Entities.BaseCurrency>;
using V2Trade = UniswapSharp.V2.Entities.Trade<UniswapSharp.Core.Entities.BaseCurrency, UniswapSharp.Core.Entities.BaseCurrency>;
using V3Pool = UniswapSharp.V3.Entities.Pool;
using V3Route = UniswapSharp.V3.Entities.Route<UniswapSharp.Core.Entities.BaseCurrency, UniswapSharp.Core.Entities.BaseCurrency>;
using V3Trade = UniswapSharp.V3.Entities.Trade<UniswapSharp.Core.Entities.BaseCurrency, UniswapSharp.Core.Entities.BaseCurrency>;
using V4Pool = UniswapSharp.V4.Entities.Pool;
using MixedTrade = UniswapSharp.Router.Entities.MixedRoute.MixedRouteTrade<UniswapSharp.Core.Entities.BaseCurrency, UniswapSharp.Core.Entities.BaseCurrency>;
using MixedSDK = UniswapSharp.Router.Entities.MixedRoute.MixedRouteSDK<UniswapSharp.Core.Entities.BaseCurrency, UniswapSharp.Core.Entities.BaseCurrency>;
using RouterTrade = UniswapSharp.Router.Entities.Trade<UniswapSharp.Core.Entities.BaseCurrency, UniswapSharp.Core.Entities.BaseCurrency>;
using Tick = UniswapSharp.V3.Entities.Tick;
using FeeAmount = UniswapSharp.V3.Constants.FeeAmount;

namespace UniswapSharp.Testing.Router;

// Ported from sdks/router-sdk/src/swapRouter.test.ts (#swapCallParameters subset, calldata byte-verified)
public class SwapRouterTests
{
    private static readonly Ether ETHER = Ether.OnChain(1);
    private static readonly Token WETH = Weth9.Tokens[1];
    private static readonly Token token0 = new(1, "0x0000000000000000000000000000000000000001", 18, "t0", "token0");
    private static readonly Token token1 = new(1, "0x0000000000000000000000000000000000000002", 18, "t1", "token1");
    private static readonly Token token2 = new(1, "0x0000000000000000000000000000000000000003", 18, "t2", "token2");

    private const FeeAmount feeAmount = FeeAmount.MEDIUM;
    private static readonly BigInteger sqrtRatioX96 = EncodeSqrtRatioX96.Encode(1, 1);
    private const int liquidity = 1_000_000;
    private const int SPACING = 60;

    private static List<Tick> Ticks(int liq) => new()
    {
        new(NearestUsableTick.Find(TickMath.MIN_TICK, SPACING), liq, liq),
        new(NearestUsableTick.Find(TickMath.MAX_TICK, SPACING), -liq, liq),
    };

    private static V3Pool MakeV3Pool(Token a, Token b, int liq) =>
        new(a, b, feeAmount, sqrtRatioX96, liq, TickMath.GetTickAtSqrtRatio(sqrtRatioX96), Ticks(liq));

    private static V4Pool MakeV4Pool(Token a, Token b, int liq) =>
        new(a, b, (int)feeAmount, SPACING, UniswapSharp.Router.Constants.ADDRESS_ZERO, sqrtRatioX96, liq, TickMath.GetTickAtSqrtRatio(sqrtRatioX96), Ticks(liq));

    private static V2Pair MakePair(Token a, Token b, int liq) =>
        new(CurrencyAmount<Token>.FromRawAmount(a, liq), CurrencyAmount<Token>.FromRawAmount(b, liq));

    private static readonly V3Pool pool_V3_0_1 = MakeV3Pool(token0, token1, liquidity);
    private static readonly V4Pool pool_V4_0_1 = MakeV4Pool(token0, token1, liquidity);
    private static readonly V2Pair pair_0_1 = MakePair(token0, token1, liquidity);
    private static readonly V2Pair pair_1_2 = MakePair(token1, token2, liquidity);
    private static readonly V3Pool pool_V3_1_WETH = MakeV3Pool(token1, WETH, liquidity);
    private static readonly V2Pair pair_1_WETH = MakePair(token1, WETH, liquidity);
    private static readonly V2Pair pair_2_WETH = MakePair(token2, WETH, liquidity);
    private static readonly V3Pool pool_V3_2_WETH = MakeV3Pool(token2, WETH, liquidity);

    private static readonly Percent slippageTolerance = new(1, 100);
    private const string recipient = "0x0000000000000000000000000000000000000003";

    private static SwapOptions Opts() => new()
    {
        SlippageTolerance = slippageTolerance,
        Recipient = recipient,
        DeadlineOrPreviousBlockhash = 123,
    };

    private static CurrencyAmount<BaseCurrency> CB(BaseCurrency c, long v) => CurrencyAmount<BaseCurrency>.FromRawAmount(c, v);

    private static V2Route MkV2(IEnumerable<V2Pair> pairs, BaseCurrency i, BaseCurrency o) => new(pairs.ToList(), i, o);
    private static V3Route MkV3(IEnumerable<V3Pool> pools, BaseCurrency i, BaseCurrency o) => new(pools.ToList(), i, o);
    private static MixedSDK MkMixed(IEnumerable<object> pools, BaseCurrency i, BaseCurrency o) => new(pools.ToList(), i, o);

    private static Task<RouterTrade> FromRoutes(
        List<(V2Route, CurrencyAmount<BaseCurrency>)> v2,
        List<(V3Route, CurrencyAmount<BaseCurrency>)> v3,
        TradeType t,
        List<(MixedSDK, CurrencyAmount<BaseCurrency>)>? mixed = null) =>
        RouterTrade.FromRoutes(v2, v3, t, mixed);

    private static readonly List<(V2Route, CurrencyAmount<BaseCurrency>)> NoV2 = new();
    private static readonly List<(V3Route, CurrencyAmount<BaseCurrency>)> NoV3 = new();

    // ==== single-hop exact input (v2 + v3) ====
    private const string SingleInExpected = "";

    [Fact]
    public async Task SingleHopExactInput_Array()
    {
        var v2 = V2Trade.ExactIn(MkV2(new[] { pair_0_1 }, token0, token1), CB(token0, 100));
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_0_1 }, token0, token1), CB(token0, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(new object[] { v2, v3 }, Opts());
        Assert.Equal(SingleInExpected, r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task SingleHopExactInput_Meta()
    {
        var trades = await FromRoutes(
            new() { (MkV2(new[] { pair_0_1 }, token0, token1), CB(token0, 100)) },
            new() { (MkV3(new[] { pool_V3_0_1 }, token0, token1), CB(token0, 100)) },
            TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(trades, Opts());
        Assert.Equal(SingleInExpected, r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    // ==== single-hop exact output (v2 + v3) ====
    private const string SingleOutExpected = "";

    [Fact]
    public async Task SingleHopExactOutput_Array()
    {
        var v2 = V2Trade.ExactOut(MkV2(new[] { pair_0_1 }, token0, token1), CB(token1, 100));
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_0_1 }, token0, token1), CB(token1, 100), TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(new object[] { v2, v3 }, Opts());
        Assert.Equal(SingleOutExpected, r.Calldata);
        Assert.Equal("0x00", r.Value);
