    [Fact]
    public async Task SingleHopExactOutput_Meta()
    {
        var trades = await FromRoutes(
            new() { (MkV2(new[] { pair_0_1 }, token0, token1), CB(token1, 100)) },
            new() { (MkV3(new[] { pool_V3_0_1 }, token0, token1), CB(token1, 100)) },
            TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(trades, Opts());
