    // ==== Mixed Route ====
    [Fact]
    public async Task MixedRoute_ThrowsWithV4Pool()
    {
        var trade = await MixedTrade.FromRoute(MkMixed(new object[] { pair_1_WETH, pool_V4_0_1 }, WETH, token0), CB(WETH, 100), TradeType.EXACT_INPUT);
        var ex = Assert.Throws<InvalidOperationException>(() => SwapRouter.SwapCallParameters(trade, Opts()));
        Assert.Equal("Encoding mixed routes with V4 not supported", ex.Message);
    }

    [Fact]
    public async Task MixedRoute_SingleHopBackwardsCompatible_Arrays()
    {
        var v2 = V2Trade.ExactIn(MkV2(new[] { pair_0_1 }, token0, token1), CB(token0, 100));
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_0_1 }, token0, token1), CB(token0, 100), TradeType.EXACT_INPUT);
        var r1 = SwapRouter.SwapCallParameters(new object[] { v2, v3 }, Opts());
        Assert.Equal(SingleInExpected, r1.Calldata);

        var m1 = await MixedTrade.FromRoute(MkMixed(new object[] { pair_0_1 }, token0, token1), CB(token0, 100), TradeType.EXACT_INPUT);
        var m2 = await MixedTrade.FromRoute(MkMixed(new object[] { pool_V3_0_1 }, token0, token1), CB(token0, 100), TradeType.EXACT_INPUT);
        var r2 = SwapRouter.SwapCallParameters(new object[] { m1, m2 }, Opts());
        Assert.Equal(SingleInExpected, r2.Calldata);
        Assert.Equal("0x00", r2.Value);
    }

    [Fact]
    public async Task MixedRoute_MultiHopBackwardsCompatible_Array()
    {
        var m1 = await MixedTrade.FromRoute(MkMixed(new object[] { pair_0_1, pair_1_WETH }, token0, WETH), CB(token0, 100), TradeType.EXACT_INPUT);
        var m2 = await MixedTrade.FromRoute(MkMixed(new object[] { pool_V3_0_1, pool_V3_1_WETH }, token0, WETH), CB(token0, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(new object[] { m1, m2 }, Opts());
        Assert.Equal(MultiInExpected, r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task MixedRoute_MultiHopBackwardsCompatible_Meta()
    {
        var m1 = await MixedTrade.FromRoute(MkMixed(new object[] { pair_0_1, pair_1_WETH }, token0, WETH), CB(token0, 100), TradeType.EXACT_INPUT);
        var m2 = await MixedTrade.FromRoute(MkMixed(new object[] { pool_V3_0_1, pool_V3_1_WETH }, token0, WETH), CB(token0, 100), TradeType.EXACT_INPUT);
        var trades = await FromRoutes(NoV2, NoV3, TradeType.EXACT_INPUT,
            new() { (m1.Swaps[0].Route, CB(token0, 100)), (m2.Swaps[0].Route, CB(token0, 100)) });
        var r = SwapRouter.SwapCallParameters(trades, Opts());
        Assert.Equal(MultiInExpected, r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    [Fact]
    public async Task MixedRoute_ConsecutivePoolsPairs()
    {
        const string expected = "";
        var m1 = await MixedTrade.FromRoute(MkMixed(new object[] { pool_V3_0_1, pool_V3_1_WETH, pair_2_WETH }, token0, WETH), CB(token0, 100), TradeType.EXACT_INPUT);
        var m2 = await MixedTrade.FromRoute(MkMixed(new object[] { pair_0_1, pair_1_2, pool_V3_2_WETH }, token0, WETH), CB(token0, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(new object[] { m1, m2 }, Opts());
        Assert.Equal(expected, r.Calldata);
        Assert.Equal("0x00", r.Value);
    }

    // ==== ETH input ====
    private const string EthInSingleInExpected = "";

    [Fact]
    public async Task EthInput_SingleHopExactInput_Array()
    {
        var v2 = V2Trade.ExactIn(MkV2(new[] { pair_1_WETH }, ETHER, token1), CB(ETHER, 100));
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_1_WETH }, ETHER, token1), CB(ETHER, 100), TradeType.EXACT_INPUT);
        var r = SwapRouter.SwapCallParameters(new object[] { v2, v3 }, Opts());
        Assert.Equal(EthInSingleInExpected, r.Calldata);
