    [Fact]
    public async Task EthInput_SingleHopExactOutput_Array_RefundEth()
    {
        const string expected = "";
        var v2 = V2Trade.ExactOut(MkV2(new[] { pair_1_WETH }, ETHER, token1), CB(token1, 100));
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_1_WETH }, ETHER, token1), CB(token1, 100), TradeType.EXACT_OUTPUT);
        var r = SwapRouter.SwapCallParameters(new object[] { v2, v3 }, Opts());
