    // ==== #swapAndAddCallParameters ====
    private static readonly V3Pool pool_V3_0_WETH = MakeV3Pool(token0, WETH, liquidity);

    private static SwapAndAddOptions AddOpts() => new() { SlippageTolerance = slippageTolerance };
    private static CondensedAddLiquidityOptions AddLiq() => new() { Recipient = "0x0000000000000000000000000000000000000006" };

    private const string SwapAndAddSingleExpected = "";

    [Fact]
    public async Task SwapAndAdd_SingleHop_V2V3()
    {
        var v2 = V2Trade.ExactIn(MkV2(new[] { pair_0_1 }, token0, token1), CB(token0, 10));
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_0_1 }, token0, token1), CB(token0, 10), TradeType.EXACT_INPUT);
        var position = new UniswapSharp.V3.Entities.Position(pool_V3_0_1, -60, 60, 1111111111);
        var r = SwapRouter.SwapAndAddCallParameters(new object[] { v2, v3 }, AddOpts(), position, AddLiq(), ApprovalTypes.NOT_REQUIRED, ApprovalTypes.NOT_REQUIRED);
        Assert.Equal(SwapAndAddSingleExpected, r.Calldata);
    }

    [Fact]
    public async Task SwapAndAdd_SingleHop_MixedV3()
    {
        var m2 = await MixedTrade.FromRoute(MkMixed(new object[] { pair_0_1 }, token0, token1), CB(token0, 10), TradeType.EXACT_INPUT);
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_0_1 }, token0, token1), CB(token0, 10), TradeType.EXACT_INPUT);
        var position = new UniswapSharp.V3.Entities.Position(pool_V3_0_1, -60, 60, 1111111111);
        var r = SwapRouter.SwapAndAddCallParameters(new object[] { m2, v3 }, AddOpts(), position, AddLiq(), ApprovalTypes.NOT_REQUIRED, ApprovalTypes.NOT_REQUIRED);
        Assert.Equal(SwapAndAddSingleExpected, r.Calldata);
    }

    [Fact]
    public async Task SwapAndAdd_MultiHop_V2V3()
    {
        const string expected = "";
        var v2 = V2Trade.ExactIn(MkV2(new[] { pair_0_1, pair_1_WETH }, token0, WETH), CB(token0, 100));
        var v3 = await V3Trade.FromRoute(MkV3(new[] { pool_V3_0_1, pool_V3_1_WETH }, token0, WETH), CB(token0, 100), TradeType.EXACT_INPUT);
        var position = new UniswapSharp.V3.Entities.Position(pool_V3_0_WETH, -60, 60, 1111111111);
        var r = SwapRouter.SwapAndAddCallParameters(new object[] { v2, v3 }, AddOpts(), position, AddLiq(), ApprovalTypes.NOT_REQUIRED, ApprovalTypes.NOT_REQUIRED);
        Assert.Equal(expected, r.Calldata);
    }
}
